const aiOutput = items[0].json.output;
const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
let data = {};

if (jsonMatch) {
  try {
    data = JSON.parse(jsonMatch[0]);
  } catch (e) {
    data = { "error": "JSON parse failed" };
  }
}

const textReply = aiOutput.replace(/\{[\s\S]*\}/, '').trim();

return [{
  json: {
    customer_reply: textReply,
    project_type: data.project_type || "",
    site: data.site || "",
    budget: data.budget || 0,
    summary: data.summary || "",
    notes: data.notes || "",
    phone: data.phone || "",
    // هنا ضفنا الحالة: لو الـ AI بعتها هناخدها، لو مبعتهاش هنخليها "قيد التأهيل" كبداية
    status: data.status || "قيد التأهيل" 
  }
}];
